"""Steel plate geometry."""

from __future__ import annotations

import math
from itertools import count
from typing import Literal, Optional

from fhecor_structuralcodes.EN1993_1_1_2005.chapter_5_structural_analysis import (
    internal_plate_elastic_class,
    internal_plate_plastic_class,
    outstand_flange_elastic_class,
    outstand_flange_plastic_class,
)
from fhecor_structuralcodes.EN1993_1_5_2006.chapter_4_plate_buckling_direct_stress import (
    beff_internal,
    beff_outstand,
    epsilon_parameter,
    k_sigma_table_4_1,
    k_sigma_table_4_2,
    lambda_p,
    rho_internal,
    rho_outstand,
    sigma_cr_c_unstiffened,
)
from fhecor_structuralcodes.core._plate_results import (
    LocalBucklingResults,
    stress_state,
)
from fhecor_structuralcodes.materials import Structural_steel
from structuralcodes.geometry import LineGeometry

Point2D = tuple[float, float]

PlatePosition = Literal["internal", "start_supported_edge", "end_supported_edge"]
# internal -> internal plate,
# start_supported_edge -> plate attached to the starting point
# end_supported_edge -> plate attached to the ending point


class Plate:
    """
    steel plate class.
    Args:
        material: material of the plate (str)
        b: width of the plate in mm (float)
        t: thickness in mm (float)
        y0: local y coordinate of the initial edge in mm (float) [possitive ->]
        z0: local z coordinate of the initial edge in mm (float) [possitive ^]
        alfa: angle of the plate in degrees from the horizontal (float) [possitive counterclockwise]
        plate_position: position of the plate - "internal", "start_supported_edge" or "end_supported_edge"
        non_buckling: if True, the plate is not allowed to buckle (bool)
    """

    _id_counter = count(1)

    def __init__(
        self,
        material: Structural_steel,
        b: float,
        t: float,
        y0: float = 0,
        z0: float = 0,
        alfa: float = 0,
        plate_position: PlatePosition = "internal",
        non_buckling: bool = False,
        plate_id: Optional[int] = None,
        origin_plate_id: Optional[int] = None,
    ):
        generated_id = next(self._id_counter) if plate_id is None else plate_id
        self.material = material
        self.plate_id = generated_id
        self.origin_plate_id = (
            generated_id if origin_plate_id is None else origin_plate_id
        )
        self.b = b
        self.t = t
        self.y0 = y0
        self.z0 = z0
        self.alfa = alfa
        self.plate_position = plate_position
        self.non_buckling = non_buckling
        self.buckling_results: Optional[LocalBucklingResults] = None
        self.stress_state: Optional[stress_state] = None

    @property
    def area(self) -> float:
        return self.b * self.t

    @property
    def centroid(self) -> tuple[float, float]:
        """
        Centroide global (y,z).
        y0,z0 corresponds to the initial edge.
        """
        alpha = math.radians(self.alfa)
        dy = (self.b / 2.0) * math.cos(alpha)
        dz = (self.b / 2.0) * math.sin(alpha)

        yc = self.y0 + dy
        zc = self.z0 + dz
        return yc, zc

    @property
    def endpoint(self) -> Point2D:
        """End point of the plate segment in global coordinates (y, z)."""
        return Plate.segment_end(self.y0, self.z0, self.b, self.alfa)

    @staticmethod
    def segment_end(y0: float, z0: float, length: float, alfa_deg: float) -> Point2D:
        """Return end point of a 2D segment defined by origin, length and angle."""
        alpha = math.radians(alfa_deg)
        return y0 + length * math.cos(alpha), z0 + length * math.sin(alpha)

    def to_line_geometry(self, material=None) -> LineGeometry:
        """Build structuralcodes line geometry from this plate.

        Args:
            material: Optional material override. If None, uses
                self.material.material_analysis.
        """
        p0 = (self.y0, self.z0)
        p1 = self.endpoint
        mat = material if material is not None else self.material.material_analysis
        return LineGeometry(line=(p0, p1), thickness=self.t, material=mat)

    def inertia_central_global(self) -> tuple[float, float, float]:
        """
        Momentos de inercia en el centroide rotados al sistema global.
        Devuelve (Iyy, Izz, Iyz)
        """
        L = self.b
        t = self.t
        alpha = math.radians(self.alfa)

        # Inercias locales centradas (CORREGIDO)
        I_ss = (L * t**3) / 12.0  # Inercia respecto al eje s (paralelo a L)
        I_nn = (t * L**3) / 12.0  # Inercia respecto al eje n (perpendicular a L)

        # Rotación al sistema global (y,z)
        c = math.cos(alpha)
        s = math.sin(alpha)

        Iyy = I_ss * c * c + I_nn * s * s
        Izz = I_ss * s * s + I_nn * c * c
        Iyz = (I_ss - I_nn) * s * c

        return Iyy, Izz, Iyz

    def update_plate_stress_state(
        self, sigma_end1: float, sigma_end2: float, alfaC: Optional[float] = None
    ) -> None:
        """
        Calculate the plate class according to EN 1993-1-1 and return the stress_state object.
        Args:
            sigma_end1: stress at the initial edge in MPa (float). Compression is negative.
            sigma_end2: stress at the end edge in MPa (float). Compression is negative.
            alfaC: if plastification exists, should be provided instead of sigma_end1 and
                sigma_end2. Is the ratio of the plate in compression and cannot be determined
                from the stresses sigma_end1 and sigma_end2.
        Return None. Just updates the stress_state attribute.
        TODO: Circular an angular sections
        """
        sigma_1 = -min(sigma_end1, sigma_end2)
        sigma_2 = -max(sigma_end1, sigma_end2)

        if sigma_end1 >= 0 and sigma_end2 >= 0:  # pure tension
            bc = 0
            bt = self.b
            class_plate = 1
            bc_initial_edge = False if sigma_end1 > 0 else True

            self.stress_state = stress_state(
                sigma_1=sigma_1,
                sigma_2=sigma_2,
                class_plate=class_plate,
                bc=bc,
                bt=bt,
                bc_initial_edge=bc_initial_edge,
            )
            return

        if alfaC is not None:  # plastic and elastic stresses
            bc = self.b * alfaC
            bt = self.b - bc
            bc_initial_edge = False if sigma_end1 > 0 else True
        elif sigma_end1 < 0 and sigma_end2 < 0:  # pure compression elastic
            bc = self.b
            bt = 0
            bc_initial_edge = True
            alfaC = 1
        else:  # mixed stress elastic (only)
            bc = self.b * sigma_1 / (sigma_1 - sigma_2)
            bt = self.b - bc
            bc_initial_edge = False if sigma_end1 > 0 else True
            alfaC = bc / self.b

        # determine the class of the plate:

        if self.plate_position == "internal":
            class_plate = internal_plate_plastic_class(
                self.b, self.t, self.material.f_y, alfaC
            )
            if class_plate == 3:
                class_plate = internal_plate_elastic_class(
                    self.b, self.t, self.material.f_y, sigma_2 / sigma_1
                )
        else:
            # sigma_1 en end1 si sigma_end1<=sigma_end2; en end2 si sigma_end2<=sigma_end1
            max_stress_at_supported_edge = (
                self.plate_position == "start_supported_edge"
                and sigma_end1 <= sigma_end2
            ) or (
                self.plate_position == "end_supported_edge" and sigma_end2 <= sigma_end1
            )
            # Compresión pura: ambos extremos comprimidos → borde apoyado nunca en tracción
            tension_at_supported_edge = (
                sigma_end1 > 0
                and self.plate_position == "start_supported_edge"
                or sigma_end2 > 0
                and self.plate_position == "end_supported_edge"
            )

            class_plate = outstand_flange_plastic_class(
                self.b,
                self.t,
                self.material.f_y,
                alfaC,
                tension_at_supported_edge,
            )
            if class_plate == 3:
                class_plate = outstand_flange_elastic_class(
                    self.b,
                    self.t,
                    self.material.f_y,
                    sigma_2 / sigma_1,
                    max_stress_at_supported_edge,
                )
        self.stress_state = stress_state(
            sigma_1=sigma_1,
            sigma_2=sigma_2,
            class_plate=class_plate,
            bc=bc,
            bt=bt,
            bc_initial_edge=bc_initial_edge,
        )

    def calculate_buckling_reductions(self, stress_state: stress_state):
        """
        Calculate the buckling analysis and reductions for the plate.
        Args:
            stress_state: stress_state object containing the class and end stresses.
        Returns:
            BucklingResults: buckling results for the plate
        """
        epsilon = epsilon_parameter(self.material.f_y)

        psi = stress_state.psi

        if psi > 0 and stress_state.sigma_1 < 0:  # tension in the whole plate
            self.buckling_results = LocalBucklingResults(rho=1.0, beff=self.b)
            return

        if self.plate_position == "internal":
            k_sigma = k_sigma_table_4_1(psi)
        else:
            k_sigma = k_sigma_table_4_2(psi)

        lambdap = lambda_p(self.b, self.t, epsilon, k_sigma)
        sigma_cr = sigma_cr_c_unstiffened(
            self.material.E, self.t, self.b, self.material.nu
        )

        if self.plate_position == "internal":
            rho = rho_internal(lambdap, psi)
            beff_dict = beff_internal(rho, self.b, psi)
            beff = beff_dict["beff"]
            be1 = beff_dict["be1"]
            be2 = beff_dict["be2"]
        else:
            rho = rho_outstand(lambdap)
            beff = beff_outstand(rho, self.b, psi)
            be1 = 0
            be2 = 0

        self.buckling_results = LocalBucklingResults(
            k_sigma=k_sigma,
            lambda_p=lambdap,
            sigma_cr=sigma_cr,
            rho=rho,
            beff=beff,
            be1=be1,
            be2=be2,
            epsilon=epsilon,
        )

    def _spawn_from_abscissa_interval(
        self, s_start: float, s_end: float
    ) -> Optional["Plate"]:
        """Create a plate copy over a [s_start, s_end] local interval."""
        width = s_end - s_start
        if width <= 0:
            return None
        alpha = math.radians(self.alfa)
        return Plate(
            material=self.material,
            b=width,
            t=self.t,
            y0=self.y0 + s_start * math.cos(alpha),
            z0=self.z0 + s_start * math.sin(alpha),
            alfa=self.alfa,
            plate_position=self.plate_position,
            non_buckling=self.non_buckling,
            origin_plate_id=self.origin_plate_id,
        )

    def build_effective_plates_class4(self) -> list["Plate"]:
        """Build EN effective geometry for a class 4 plate."""
        if self.stress_state is None or self.buckling_results is None:
            return [self]

        if self.stress_state.class_plate != 4:
            return [self]

        if self.plate_position == "internal":
            be1 = float(self.buckling_results.be1 or 0.0)
            be2 = float(self.buckling_results.be2 or 0.0)
            be1 = max(0.0, min(self.b, be1))
            be2 = max(0.0, min(self.b, be2))
            if be1 + be2 > self.b:
                scale = self.b / (be1 + be2)
                be1 *= scale
                be2 *= scale

            sigma1_at_start = bool(self.stress_state.bc_initial_edge)
            if sigma1_at_start:
                intervals = [(0.0, be1), (self.b - be2, self.b)]
            else:
                intervals = [(0.0, be2), (self.b - be1, self.b)]

            effective: list[Plate] = []
            for s_start, s_end in intervals:
                plate = self._spawn_from_abscissa_interval(s_start, s_end)
                if plate is not None:
                    effective.append(plate)
            return effective if effective else []

        beff = float(self.buckling_results.beff or 0.0)
        beff = max(0.0, min(self.b, beff))
        if self.plate_position == "start_supported_edge":
            interval = (0.0, beff)
        else:
            interval = (self.b - beff, self.b)
        plate = self._spawn_from_abscissa_interval(*interval)
        return [plate] if plate is not None else []


def assemble_inertia(
    plates: list[Plate],
    y_ref: float = 0,
    z_ref: float = 0,
) -> tuple[float, float, float]:
    """Ensambla la inercia de las chapas respecto a un punto de referencia.

    Args:
        plates: Lista de chapas.
        y_ref: Coordenada y del punto de referencia (ejes globales).
        z_ref: Coordenada z del punto de referencia (ejes globales).

    Returns:
        (Iyy, Izz, Iyz) en mm⁴ respecto al punto (y_ref, z_ref).
    """
    Iyy = 0.0
    Izz = 0.0
    Iyz = 0.0

    for p in plates:
        Iyy_c, Izz_c, Iyz_c = p.inertia_central_global()
        A = p.area
        yc, zc = p.centroid

        # Steiner al punto de referencia
        dy = yc - y_ref
        dz = zc - z_ref
        Iyy += Iyy_c + A * dz**2
        Izz += Izz_c + A * dy**2
        Iyz += Iyz_c + A * dy * dz

    return Iyy, Izz, Iyz
